SELECT 'Manager / Supervisor' as [Reports To],
       T.EMPLOYEE_ID, 
       T.TRANSACTION_DATE, 
       E.LAST_NAME, 
       E.FIRST_NAME, 
       E.DEPARTMENT_ID, 
       T.WORKORDER_BASE_ID, 
       t.resource_id, 
       T.HOURS_WORKED, 
       E.SHIFT_ID, 
       T.TRANSACTION_ID
  FROM LABOR_TICKET AS T 
 INNER JOIN EMPLOYEE AS E 
    ON T.EMPLOYEE_ID = E.ID
 WHERE T.ACT_CLOCK_OUT IS NULL
   AND T.ACT_CLOCK_IN IS NOT NULL
   AND T.HOURS_WORKED IS NULL
   AND (T.TRANSACTION_DATE >= '7/1/2016'
   AND T.TRANSACTION_DATE < '9/1/2016')
   and len(e.id) < 5
   ORDER BY E.id, E.last_NAME, E.FIRST_NAME